/** handles requests for the dot1qFdbTable table, if anything else needs to be done */
int
dot1qFdbTable_handler(
    netsnmp_mib_handler               *handler,
    netsnmp_handler_registration      *reginfo,
    netsnmp_agent_request_info        *reqinfo,
    netsnmp_request_info              *requests) {

    netsnmp_request_info *request;
    netsnmp_table_request_info *table_info;
    netsnmp_variable_list *var;
    struct commitInfo *ci = NULL;

    void *data_context = NULL;

    oid *suffix;
    size_t suffix_len;

    /** column and row index encoded portion */
    suffix = requests->requestvb->name + reginfo->rootoid_len + 1;
    suffix_len = requests->requestvb->name_length -
        (reginfo->rootoid_len + 1);

    for(request = requests; request; request = request->next) {
        var = request->requestvb;
        if (request->processed != 0)
            continue;

        switch (reqinfo->mode) {
        case MODE_GET:
            data_context =  netsnmp_extract_iterator_context(request);
            if (data_context == NULL) {
                netsnmp_set_request_error(reqinfo, request,
                                          SNMP_NOSUCHINSTANCE);
                continue;
            }
            break;

        }

        /** extracts the information about the table from the request */
        table_info = netsnmp_extract_table_info(request);
        /** table_info->colnum contains the column number requested */
        /** table_info->indexes contains a linked list of snmp variable
           bindings for the indexes of the table.  Values in the list
           have been set corresponding to the indexes of the
           request */
        if (table_info == NULL) {
            continue;
        }

        switch(reqinfo->mode) {
            case MODE_GET:
                switch(table_info->colnum) {
                    case COLUMN_DOT1QFDBID:
                            {
                                u_long *retval;
                                size_t retval_len = 0;
                                retval = get_dot1qFdbId(data_context, &retval_len);
                                if (retval)
                                    snmp_set_var_typed_value(var, ASN_UNSIGNED,
                                                         (const u_char *) retval,
                                                         retval_len);
                            }
                        break;

                    case COLUMN_DOT1QFDBDYNAMICCOUNT:
                            {
                                u_long *retval;
                                size_t retval_len = 0;
                                retval = get_dot1qFdbDynamicCount(data_context, &retval_len);
                                if (retval)
                                    snmp_set_var_typed_value(var, ASN_COUNTER,
                                                         (const u_char *) retval,
                                                         retval_len);
                            }
                        break;

                    default:
                /** We shouldn't get here */
                        snmp_log(LOG_ERR, "problem encountered in dot1qFdbTable_handler: unknown column\n");
                }
                break;


            default:
                snmp_log(LOG_ERR, "problem encountered in dot1qFdbTable_handler: unsupported mode\n");
        }
    }


    return SNMP_ERR_NOERROR;
}


